export enum Realm {
    Mortal = '凡人',
    QiRefinement = '练气',
    FoundationEstablishment = '筑基',
    Zifu = '紫府',
    JinDan = '金丹',
    YuanYing = '元婴',
    YuanShen = '化神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type TaskType = 'Cultivation' | 'Exploration' | 'Research' | 'Patrol' | 'Idle' | 'Mission';
export type TalentTier = '凡人' | '平庸' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
export type RootGrade = '凡人' | '伪灵根' | '下品灵根' | '中品灵根' | '极品灵根';
export type DevelopmentPlan = 'Combat' | 'Alchemy' | 'Smithing' | 'Talisman' | 'Balanced';
export type MethodQuality = '上等' | '中等' | '下等';
export type MethodType = 'Cultivation' | 'Combat' | 'Movement';

export type BuildingCategory = 'Resource' | 'Functional' | 'Base';

export interface Building {
    id: string;
    type: string;
    level: number;
    assignedMemberId: string | null;
    isFinished: boolean;
    turnsRemaining: number;
}

export interface Inventory {
    herbs: Record<string, number>;
    minerals: Record<string, number>;
    paper: number;
    pills: Record<string, number>;
    weapons: Record<string, number>;
    methods: Record<string, number>;
}

export interface MethodBuffs {
    cultivationSpeed?: number;
    attack?: number;
    defense?: number;
    divineSense?: number;
    maxAge?: number;
}

export interface CultivationMethod {
    id: string;
    name: string;
    grade: number;
    quality: MethodQuality;
    type: MethodType;
    element: Element | '无';
    desc: string;
    bonus: string;
    buffs: MethodBuffs;
}

export interface ElementalRoots {
    gold: number;
    wood: number;
    water: number;
    fire: number;
    earth: number;
}

export interface SpecializedTalents {
    战斗天赋: {
        剑法: number;
        拳法: number;
        枪法: number;
        刀法: number;
        弓箭: number;
    };
    百艺天赋: {
        炼丹: number;
        炼器: number;
        制符: number;
        阵法: number;
    };
}

export interface ClanMember {
    id: string;
    name: string;
    title?: string; 
    gender: '男' | '女';
    generation: number; 
    realm: Realm;
    subRealm: number; 
    age: number;
    maxAge: number;
    physique: string;
    aptitude: number;
    comprehension: number;
    divineSense: number;
    roots: ElementalRoots;
    rootGrade: RootGrade;
    talents: SpecializedTalents;
    proficiencies: Record<keyof SpecializedTalents['百艺天赋'], number>;
    combatProficiencies: Record<keyof SpecializedTalents['战斗天赋'], number>;
    tier: TalentTier;

    element: Element;
    status: 'healthy' | 'injured' | 'dead';
    loyalty: number; 
    assignment: TaskType;
    legacyPoints: number; 
    deathYear?: number;

    mainMethodId: string | null;
    movementMethodId: string | null;
    auxMethodIds: string[];

    equippedItems: {
        weapon: string | null;
        armor: string | null;
        accessory: string | null;
        treasure: string | null;
    };
    personalInventory: Inventory;

    cultivationProgress: number;
    developmentPlan: DevelopmentPlan;
    divineAbilities: string[];
    sect: string;
    position: string;
}

export type RegionCategory = 'Natural' | 'Stakeholder' | 'Mystic';
export type RegionType = 'lake' | 'mountain' | 'forest' | 'city' | 'sect' | 'ruins' | 'cave' | 'island' | 'desert';

export type FactionType = '望月李氏' | '北寒宗' | '天一剑宗' | '邵家' | '魏家' | '离火门' | '南海散修' | '无';

export interface Region {
    id: string;
    name: string;
    description: string;
    difficulty: number;
    owner: FactionType;
    x: number;
    y: number;
    type: RegionType;
    category: RegionCategory;
    isDiscovered: boolean;
    resources: string[];

    // 领土控制逻辑
    controlValue: number; // 0-100, 李家控制力
    occupancyStatus: 'idle' | 'contested' | 'secured'; 

    activeMission?: {
        memberId: string;
        turnsRemaining: number;
        totalTurns: number;
    };
}

export interface GameState {
    year: number;
    spiritStones: number;
    merit: number; 
    luck: number; 
    members: ClanMember[];
    regions: Region[];
    buildings: Building[];
    inventory: Inventory;
    currentRegionId: string;
    isMirrorActive: boolean;
    logs: string[];
    heritagePool: number;
}

import React, { useState, useMemo } from 'react';
import { Region, RegionType, ClanMember, RegionCategory, Realm, FactionType } from '../types';

interface Props {
    regions: Region[];
    members: ClanMember[];
    onSelectRegion: (region: Region | null) => void;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onUpdateRegion: (id: string, updates: Partial<Region>) => void;
    currentRegionId: string;
}

const WorldMap: React.FC<Props> = ({ regions, members, onSelectRegion, onUpdateMember, onUpdateRegion, currentRegionId }) => {
    const [hoveredRegionId, setHoveredRegionId] = useState<string | null>(null);

    const selectedRegion = regions.find(r => r.id === currentRegionId);
    const idleMembers = members.filter(m => m.status === 'healthy' && (m.assignment === 'Idle' || m.assignment === 'Patrol'));
    const hoveredRegion = regions.find(r => r.id === hoveredRegionId);

    const getFactionColor = (faction: FactionType) => {
        switch (faction) {
            case '望月李氏': return 'rgba(234, 179, 8, 0.4)'; // 金色
            case '北寒宗': return 'rgba(59, 130, 246, 0.4)'; // 蓝色
            case '天一剑宗': return 'rgba(239, 68, 68, 0.4)'; // 红色
            case '离火门': return 'rgba(249, 115, 22, 0.4)'; // 橙色
            case '魏家': return 'rgba(139, 92, 246, 0.4)'; // 紫色
            case '邵家': return 'rgba(34, 197, 94, 0.4)'; // 绿色
            default: return 'transparent';
        }
    };

    const getTypeIcon = (type: RegionType, category: RegionCategory) => {
        if (category === 'Mystic') return '✨';
        switch (type) {
            case 'lake': return '🌊';
            case 'mountain': return '⛰️';
            case 'forest': return '🌿';
            case 'city': return '🏮';
            case 'sect': return '⛩️';
            case 'ruins': return '🏺';
            case 'cave': return '🕳️';
            case 'island': return '🏝️';
            case 'desert': return '🏜️';
            default: return '📍';
        }
    };

    const handleDispatch = (memberId: string, region: Region) => {
        let turns = 1;
        if (region.category === 'Natural') turns = 1 + Math.floor(region.difficulty / 3);
        if (region.category === 'Mystic') turns = 3 + Math.floor(region.difficulty / 2);

        onUpdateMember(memberId, { assignment: 'Mission' });
        onUpdateRegion(region.id, {
            activeMission: {
                memberId,
                turnsRemaining: turns,
                totalTurns: turns
            }
        });
    };

    const getPanelStyle = () => {
        if (!selectedRegion) return {};
        const isRightSide = selectedRegion.x < 50;
        const isBottomSide = selectedRegion.y < 50;

        return {
            left: isRightSide ? `${selectedRegion.x}%` : 'auto',
            right: !isRightSide ? `${100 - selectedRegion.x}%` : 'auto',
            top: isBottomSide ? `${selectedRegion.y}%` : 'auto',
            bottom: !isBottomSide ? `${100 - selectedRegion.y}%` : 'auto',
            transform: `translate(${isRightSide ? '40px' : '-40px'}, ${isBottomSide ? '20px' : '-20px'})`,
        };
    };

    // 势力势力光环背景
    const factionZones = useMemo(() => {
        return regions.filter(r => r.isDiscovered && r.owner !== '无').map(r => (
            <div 
                key={`zone-${r.id}`}
                className="absolute transform -translate-x-1/2 -translate-y-1/2 rounded-full blur-[80px] pointer-events-none transition-all duration-1000"
                style={{ 
                    left: `${r.x}%`, 
                    top: `${r.y}%`, 
                    width: '300px', 
                    height: '300px', 
                    background: getFactionColor(r.owner),
                    opacity: 0.15
                }}
            />
        ));
    }, [regions]);

    return (
        <div className="relative w-full h-full parchment scroll-shadow overflow-hidden border-8 border-[#4a3728] bg-[#e6d5b8]">
            {/* 地图底纹渲染 */}
            <div className="absolute inset-0 opacity-10 pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/aged-paper.png')]"></div>

            {/* 势力势力圈 */}
            <div className="absolute inset-0 z-0">
                {factionZones}
            </div>

            <div className="absolute top-6 left-1/2 -translate-x-1/2 text-5xl font-cursive opacity-20 select-none pointer-events-none z-10">
                天罡大陆 · 九州全志
            </div>

            {/* 地图线条 (山脉连线/河流示意) */}
            <svg width="100%" height="100%" className="absolute inset-0 opacity-20 pointer-events-none">
                <path d="M50,150 C150,100 250,200 450,150 S650,50 850,250" stroke="#2c1810" fill="none" strokeWidth="1" strokeDasharray="5,5" />
                <path d="M100,500 Q300,400 500,550 T900,450" stroke="#2c1810" fill="none" strokeWidth="2" opacity="0.4" />
                {/* 势力边界线示意 */}
                <circle cx="50%" cy="75%" r="15%" fill="none" stroke="rgba(234, 179, 8, 0.2)" strokeWidth="1" strokeDasharray="10,5" />
            </svg>

            {regions.map(region => {
                const isDiscovered = region.isDiscovered;
                const isHome = region.id === 'li_clan_home';
                const isOccupied = !!region.activeMission;
                const currentOwner = region.owner;

                if (!isDiscovered) {
                    return (
                        <div 
                            key={region.id}
                            className="absolute transform -translate-x-1/2 -translate-y-1/2 opacity-30 cursor-help group"
                            style={{ left: `${region.x}%`, top: `${region.y}%` }}
                        >
                            <div className="w-8 h-8 flex items-center justify-center bg-black/10 rounded-full text-lg grayscale blur-[0.5px] hover:grayscale-0 hover:blur-0 transition-all">
                                ❔
                            </div>
                            <div className="absolute hidden group-hover:block top-10 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[8px] px-2 py-1 rounded whitespace-nowrap z-50">
                                动用昊天镜可照破此地虚妄
                            </div>
                        </div>
                    );
                }

                return (
                    <button
                        key={region.id}
                        onClick={() => onSelectRegion(region)}
                        onMouseEnter={() => setHoveredRegionId(region.id)}
                        onMouseLeave={() => setHoveredRegionId(null)}
                        className={`absolute transform -translate-x-1/2 -translate-y-1/2 transition-all duration-500 group
                            ${currentRegionId === region.id ? 'scale-125 z-20' : 'hover:scale-110 z-10'}`}
                        style={{ left: `${region.x}%`, top: `${region.y}%` }}
                    >
                        <div className="flex flex-col items-center">
                            {/* 控制力进度条 */}
                            {region.category !== 'Stakeholder' && (
                                <div className="w-8 h-1 bg-black/20 rounded-full overflow-hidden mb-1 border border-[#4a3728]/20">
                                    <div 
                                        className="h-full bg-yellow-600 shadow-[0_0_5px_rgba(234,179,8,0.5)] transition-all" 
                                        style={{ width: `${region.controlValue}%` }}
                                    ></div>
                                </div>
                            )}

                            <div className={`w-10 h-10 flex items-center justify-center rounded-full border-2 relative
                                ${isHome ? 'bg-amber-900 border-yellow-500 shadow-[0_0_15px_rgba(245,158,11,0.5)]' : (currentRegionId === region.id ? 'bg-red-900 border-yellow-400 shadow-[0_0_20px_rgba(234,179,8,0.6)]' : 'bg-[#4a3728] border-[#2c1810]')} 
                                text-xl shadow-lg transition-colors`}>
                                {getTypeIcon(region.type, region.category)}

                                {isOccupied && (
                                    <div className="absolute -top-2 -right-2 w-5 h-5 bg-orange-600 rounded-full border border-white text-[10px] flex items-center justify-center animate-bounce text-white font-bold">
                                        ⏳
                                    </div>
                                )}

                                {/* 势力标识 */}
                                {currentOwner !== '无' && !isHome && (
                                    <div 
                                        className="absolute -bottom-1 -right-1 w-4 h-4 rounded-full border border-white/50"
                                        style={{ backgroundColor: getFactionColor(currentOwner).replace('0.4', '1') }}
                                    />
                                )}
                            </div>
                            <div className="mt-1">
                                <span className={`text-[9px] font-bold bg-[#f4e4bc]/95 px-1.5 py-0.5 rounded border border-[#4a3728] whitespace-nowrap shadow-sm
                                    ${currentRegionId === region.id || isHome || region.controlValue > 80 ? 'text-amber-900 border-amber-900 ring-1 ring-amber-400' : 'text-[#2c1810]'}`}>
                                    {region.name}
                                </span>
                            </div>
                        </div>
                    </button>
                );
            })}

            {hoveredRegion && hoveredRegionId !== currentRegionId && hoveredRegion.isDiscovered && (
                <div 
                    className="absolute z-[100] pointer-events-none bg-[#1e1410] text-white p-3 rounded-md shadow-[0_10px_30px_rgba(0,0,0,0.6)] border border-yellow-900/40 min-w-[150px] animate-fade-in"
                    style={{ left: `${hoveredRegion.x}%`, top: `${hoveredRegion.y - 12}%`, transform: 'translateX(-50%)' }}
                >
                    <div className="flex justify-between items-center mb-1">
                        <p className="text-xs font-bold text-yellow-500">{hoveredRegion.name}</p>
                        <span className="text-[8px] bg-yellow-900/30 px-1 rounded text-yellow-600">难 {hoveredRegion.difficulty}</span>
                    </div>
                    <p className="text-[9px] text-gray-400 mb-1">所属：<span className="text-orange-400 font-bold">{hoveredRegion.owner}</span></p>
                    <div className="w-full bg-black/40 h-1 rounded-full overflow-hidden mt-1 mb-2">
                        <div className="h-full bg-yellow-600" style={{ width: `${hoveredRegion.controlValue}%` }}></div>
                    </div>
                    <p className="text-[8px] text-gray-500 italic line-clamp-2">{hoveredRegion.description}</p>
                </div>
            )}

            {selectedRegion && selectedRegion.isDiscovered && (
                <div 
                    className={`absolute z-30 animate-scale-in flex flex-col pointer-events-auto`}
                    style={getPanelStyle()}
                >
                    <div className="w-72 sm:w-80 bg-[#1e1410] border-2 border-yellow-900/40 rounded-lg shadow-[0_20px_50px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col max-h-[70vh]">
                        <div className="p-3 border-b border-yellow-900/20 bg-[#2c1810]/80 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-2">
                                <div className="text-lg">{getTypeIcon(selectedRegion.type, selectedRegion.category)}</div>
                                <div>
                                    <h3 className="text-yellow-500 font-bold text-sm">
                                        {selectedRegion.name}
                                    </h3>
                                    <p className="text-[9px] text-yellow-800 uppercase tracking-widest font-bold">
                                        占领势力: {selectedRegion.owner}
                                    </p>
                                </div>
                            </div>
                            <button 
                                onClick={(e) => { e.stopPropagation(); onSelectRegion(null); }}
                                className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-red-900/30 text-gray-500 hover:text-red-500 transition-colors text-xl font-bold"
                            >
                                ×
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-[#1e1410]/95 backdrop-blur-sm custom-scrollbar">
                            <p className="text-[11px] text-gray-400 italic leading-relaxed border-l-2 border-yellow-900/30 pl-2 py-1">
                                {selectedRegion.description}
                            </p>

                            <div className="flex flex-wrap gap-1.5">
                                {selectedRegion.resources.map(r => (
                                    <span key={r} className="bg-yellow-900/10 text-yellow-700 px-2 py-0.5 rounded text-[9px] border border-yellow-900/10 font-bold">
                                        • {r}
                                    </span>
                                ))}
                            </div>

                            <div className="pt-2 border-t border-yellow-900/10">
                                {selectedRegion.activeMission ? (
                                    <div className="p-4 bg-orange-900/10 rounded border border-orange-900/20 text-center space-y-2">
                                        <p className="text-xs text-orange-400 font-bold">家族子弟探索中...</p>
                                        <div className="w-full bg-black/40 h-2 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-orange-500 shadow-[0_0_10px_rgba(249,115,22,0.5)]" 
                                                style={{ width: `${(1 - selectedRegion.activeMission.turnsRemaining / selectedRegion.activeMission.totalTurns) * 100}%` }}
                                            ></div>
                                        </div>
                                        <p className="text-[10px] text-gray-500">还需持恒 {selectedRegion.activeMission.turnsRemaining} 年</p>
                                    </div>
                                ) : (
                                    <>
                                        {selectedRegion.id !== 'li_clan_home' ? (
                                            <>
                                                <div className="flex justify-between items-center mb-3">
                                                    <h4 className="text-[10px] text-yellow-600 font-bold uppercase">派遣人手</h4>
                                                    <span className="text-[9px] text-gray-600 font-sans">李家影响力: {selectedRegion.controlValue}%</span>
                                                </div>

                                                <div className="space-y-1.5">
                                                    {idleMembers.length > 0 ? (
                                                        idleMembers.map(member => (
                                                            <div key={member.id} className="bg-black/30 border border-yellow-900/5 hover:border-yellow-700/30 rounded p-2.5 flex justify-between items-center transition-all group">
                                                                <div className="flex flex-col">
                                                                    <span className="text-xs text-yellow-100 group-hover:text-yellow-500 font-bold">{member.name}</span>
                                                                    <span className="text-[9px] text-gray-500 font-sans">{member.realm === Realm.Mortal ? '凡人' : `${member.realm}${member.subRealm}层`}</span>
                                                                </div>
                                                                <button 
                                                                    onClick={() => handleDispatch(member.id, selectedRegion)}
                                                                    className="px-3 py-1 bg-yellow-900/20 hover:bg-yellow-700 text-yellow-600 hover:text-white text-[10px] rounded border border-yellow-900/30 transition-all font-bold"
                                                                >
                                                                    {selectedRegion.owner === '望月李氏' ? '驻守' : '占领'}
                                                                </button>
                                                            </div>
                                                        ))
                                                    ) : (
                                                        <p className="text-center py-4 text-[11px] text-gray-700 italic border border-dashed border-white/5 rounded">族中暂时无人可用</p>
                                                    )}
                                                </div>
                                            </>
                                        ) : (
                                            <div className="p-4 bg-blue-900/10 rounded border border-blue-900/20 text-center">
                                                <p className="text-xs text-blue-400 font-bold">李氏祖基，万世不易</p>
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>

                        <div className="p-2 bg-black/60 text-center border-t border-yellow-900/10 shrink-0">
                            <p className="text-[9px] text-gray-600 uppercase font-bold tracking-widest">
                                {selectedRegion.category === 'Mystic' ? '🏺 古老秘境' : (selectedRegion.category === 'Stakeholder' ? '🏰 势力据点' : '🌿 灵机资源')}
                            </p>
                        </div>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes scale-in {
                    from { opacity: 0; transform: scale(0.95); }
                    to { opacity: 1; transform: scale(1); }
                }
                .animate-scale-in {
                    animation: scale-in 0.2s cubic-bezier(0.16, 1, 0.3, 1) forwards;
                }
                .custom-scrollbar::-webkit-scrollbar { width: 4px; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #3d2b24; border-radius: 10px; }
                @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
                .animate-fade-in { animation: fade-in 0.2s ease-out forwards; }
            `}</style>
        </div>
    );
};

export default WorldMap;

import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, SpecializedTalents } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, getWeaponTalentBonus } from './constants';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import { generateYearlyEvent } from './services/geminiService';

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        spiritStones: 1200,
        merit: 100,
        luck: 50,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: {
            herbs: { "灵谷草": 15, "清灵花": 5, "回气草": 5, "玉露根": 5 },
            minerals: { "精铁": 20 },
            paper: 5,
            pills: {},
            weapons: {},
            methods: {}
        },
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。"],
        heritagePool: 0,
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let updatedMembers = [...prev.members];
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            if (updates.position === '老祖') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '老祖' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers.map(m => m.id === id ? { ...m, ...updates } : m)
            };
        });
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 100;
        let bonusHerbs: Record<string, number> = {};

        // 建筑与资源产出逻辑
        const updatedBuildings = state.buildings.map(b => {
            if (!b.isFinished) {
                const remaining = b.turnsRemaining - 1;
                if (remaining <= 0) {
                    yearLogs.push(`【营建】${BUILDING_TYPES[b.type].name} 终于落成！`);
                    return { ...b, isFinished: true, turnsRemaining: 0 };
                }
                return { ...b, turnsRemaining: remaining };
            }
            if (b.type === 'Market' && b.assignedMemberId) stoneGain += 200;
            if (b.type === 'SpiritField') {
                const pool = ["灵谷草", "清灵花", "回气草", "玉露根"];
                const pick = pool[Math.floor(Math.random() * pool.length)];
                bonusHerbs[pick] = (bonusHerbs[pick] || 0) + 10;
            }
            return b;
        });

