/**
 * 获取百艺加成 (基于基础天赋属性 1-10)
 */
export const getArtisanBonus = (talentLevel: number): number => {
    if (talentLevel <= 5) return 0;
    if (talentLevel === 6) return 2;
    if (talentLevel === 7) return 5;
    if (talentLevel === 8) return 7;
    if (talentLevel === 9) return 10;
    if (talentLevel === 10) return 15;
    return 0;
};

/**
 * 获取武器天赋熟练度获取加成 (1-10)
 */
export const getWeaponTalentBonus = (talentLevel: number): number => {
    if (talentLevel <= 5) return 0;
    if (talentLevel === 6) return 2;
    if (talentLevel === 7) return 5;
    if (talentLevel === 8) return 7;
    if (talentLevel === 9) return 10;
    if (talentLevel === 10) return 20;
    return 0;
};

/**
 * 获取武器等级称号 (基于熟练度)
 */
export const getWeaponMasteryTitle = (type: string, proficiency: number): string => {
    if (proficiency < 100) return `${type}初学`;
    if (proficiency < 500) return `${type}小成`;
    if (proficiency < 1000) return `${type}大成`;
    if (proficiency < 2500) return `${type}圆满`;
    if (proficiency < 5000) return `${type.replace('法', '道')}大师`;
    return `${type.replace('法', '道')}宗师`;
};

/**
 * 获取职业等级称号 (完全基于熟练度)
 */
export const getArtisanTitle = (type: string, proficiency: number): string => {
    const getThreshold = (rank: number): number => {
        if (rank <= 0) return 0;
        if (rank === 1) return 10;
        return 10 + 50 * rank * (rank - 1);
    };

    if (proficiency < getThreshold(1)) return `${type}学徒`;

    let currentRank = 1;
    for (let r = 9; r >= 1; r--) {
        if (proficiency >= getThreshold(r)) {
            currentRank = r;
            break;
        }
    }

    const numerals = ['', '一', '二', '三', '四', '五', '六', '七', '八', '九'];
    return `${numerals[currentRank]}品${type}师`;
};

import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, SpecializedTalents } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, getWeaponTalentBonus } from './constants';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import { generateYearlyEvent } from './services/geminiService';

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        spiritStones: 1200,
        merit: 100,
        luck: 50,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: {
            herbs: { "灵谷草": 15, "清灵花": 5, "回气草": 5, "玉露根": 5 },
            minerals: { "精铁": 20 },
            paper: 5,
            pills: {},
            weapons: {},
            methods: { "吐纳功": 5, "归元诀": 1, "金锋术": 2, "疾风步": 2 } // 初始家族功法存量
        },
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。"],
        heritagePool: 0,
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let updatedMembers = [...prev.members];
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            if (updates.position === '老祖') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '老祖' && m.id !== id) ? { ...m, position: '长老' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers.map(m => m.id === id ? { ...m, ...updates } : m)
            };
        });
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 100;
        let bonusHerbs: Record<string, number> = {};

        // 建筑与资源产出逻辑
        const updatedBuildings = state.buildings.map(b => {
            if (!b.isFinished) {
                const remaining = b.turnsRemaining - 1;
                if (remaining <= 0) {
                    yearLogs.push(`【营建】${BUILDING_TYPES[b.type].name} 终于落成！`);
                    return { ...b, isFinished: true, turnsRemaining: 0 };
                }
                return { ...b, turnsRemaining: remaining };
            }
            if (b.type === 'Market' && b.assignedMemberId) stoneGain += 200;
            if (b.type === 'SpiritField') {
                const pool = ["灵谷草", "清灵花", "回气草", "玉露根"];
                const pick = pool[Math.floor(Math.random() * pool.length)];
                bonusHerbs[pick] = (bonusHerbs[pick] || 0) + 10;
            }
            return b;
        });

        // 区域任务与势力对抗逻辑
        const updatedRegions = state.regions.map(r => {
            let nr = { ...r };

            // 派遣任务逻辑
            if (nr.activeMission) {
                const rem = nr.activeMission.turnsRemaining - 1;
                if (rem <= 0) {
                    const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                    if (member) {
                        yearLogs.push(`【探查】${member.name} 完成了在 ${nr.name} 的指派任务。`);
                        // 占领/控制逻辑
                        nr.controlValue = Math.min(100, nr.controlValue + 20 + Math.floor(member.aptitude / 10));
                        if (nr.controlValue >= 100) {
                            nr.owner = '望月李氏';
                            nr.occupancyStatus = 'secured';
                            yearLogs.push(`【版图】望月李氏已完全掌控 ${nr.name}！`);
                        }
                    }
                    nr.activeMission = undefined;
                } else {
                    nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                }
            } else if (nr.id !== 'li_clan_home') {
                // AI 势力对抗：自然衰减或随机变动
                if (nr.owner === '望月李氏' && nr.controlValue < 100) {
                    // 驻守族人不足，控制力缓慢下降
                    nr.controlValue = Math.max(0, nr.controlValue - 2);
                    if (nr.controlValue < 50) {
                        nr.occupancyStatus = 'contested';
                    }
                }
            }
            return nr;
        });

        const updatedMembers = state.members.map(m => {
            if (m.status === 'dead') return m;
            let nm = { ...m, age: m.age + 1 };
            // Fix for line 123 issue: Ensure Object.values returns number array to prevent unknown type comparison error in some environments
            const hasRoots = (Object.values(nm.roots) as number[]).some(v => v > 0);

            if (nm.assignment === 'Cultivation' && hasRoots && nm.realm !== Realm.Mortal) {
                nm.cultivationProgress += (nm.aptitude / 10) + 5;
                if (nm.cultivationProgress >= 100) {
                    nm.cultivationProgress = 0;
                    if (nm.subRealm < 9) nm.subRealm += 1;
                    else {
                        const idx = REALM_ORDER.indexOf(nm.realm);
                        if (idx < REALM_ORDER.length - 1) {
                            nm.realm = REALM_ORDER[idx + 1]; nm.subRealm = 1; nm.maxAge += 100;
                            yearLogs.push(`【突破】${nm.name} 踏入 ${nm.realm} 境界！`);
                        }
                    }
                }
            }

            if (nm.age >= nm.maxAge) {
                nm.status = 'dead'; nm.deathYear = state.year;
                yearLogs.push(`【陨落】家族长辈 ${nm.name} 驾鹤西去。`);
            }

            // 归还执行完任务的族人
            if (nm.assignment === 'Mission') {
                const missionRegion = updatedRegions.find(r => r.activeMission?.memberId === nm.id);
                if (!missionRegion) nm.assignment = 'Idle';
            }

            return nm;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers, regions: updatedRegions });

        setState(prev => {
            const newHerbs = { ...prev.inventory.herbs };
            Object.entries(bonusHerbs).forEach(([name, count]) => {
                newHerbs[name] = (newHerbs[name] || 0) + count;
            });
            return {
                ...prev,
                year: prev.year + 1,
                members: updatedMembers,
                buildings: updatedBuildings,
                regions: updatedRegions,
                spiritStones: prev.spiritStones + stoneGain,
                inventory: { ...prev.inventory, herbs: newHerbs },
                logs: [...yearLogs, ...prev.logs].slice(0, 15)
            };
        });
        setEvent(newEvent);
        setIsProcessing(false);
    };

    const handleUseHaotianMirror = () => {
        if (state.merit < 20) return;

        const undiscovered = state.regions.filter(r => !r.isDiscovered);
        if (undiscovered.length === 0) {
            setState(p => ({ ...p, logs: ["【昊天镜】镜光流转，天罡大陆已尽在老祖掌握之中。", ...p.logs].slice(0, 15) }));
            return;
        }

        const reveal = undiscovered[Math.floor(Math.random() * undiscovered.length)];
        setState(prev => ({
            ...prev,
            merit: prev.merit - 20,
            regions: prev.regions.map(r => r.id === reveal.id ? { ...r, isDiscovered: true } : r),
            logs: [`【昊天镜】镜光贯穿虚空，照破了 ${reveal.name} 的迷雾！`, ...prev.logs].slice(0, 15)
        }));
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') {
            setIsManagementVisible(true);
            setState(p => ({ ...p, currentRegionId: '' }));
        } else {
            setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
        }
    };

    return (
        <div className="h-screen w-screen flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl">
                <div className="flex items-center gap-12">
                    <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">族中功德</span>
                            <span className="text-lg font-mono text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button 
                        onClick={handleUseHaotianMirror} 
                        disabled={state.merit < 20}
                        className="px-5 py-2 bg-gradient-to-r from-blue-900 to-indigo-900 border border-blue-400 text-blue-100 rounded-full text-xs font-bold hover:brightness-125 transition-all shadow-[0_0_15px_rgba(59,130,246,0.4)] disabled:opacity-30"
                    >
                        🪞 昊天镜 (20功德)
                    </button>
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>📜 族谱</button>
                    <button onClick={handleNextYear} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">{isProcessing ? '推演中' : '岁过一载'}</button>
                </div>
            </header>
            <main className="flex-1 flex overflow-hidden">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />
                    <div className={`absolute bottom-6 left-6 transition-all duration-500 parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-56'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5">
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)} className="text-[#4a3728] hover:text-black">{isConsoleCollapsed ? '▲' : '▼'}</button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-2.5 text-[11px]">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold"><span className="text-[#8b0000] mr-2">◈</span> {log}</p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
                {isDashboardVisible && <div className="w-80 h-full border-l border-yellow-900/50"><ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={() => {}} /></div>}
            </main>
            {isManagementVisible && <ClanManagement state={state} onUpdateMember={handleUpdateMember} onAddBuilding={() => {}} onAssignBuilding={() => {}} onClose={() => setIsManagementVisible(false)} />}
            {event && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-[#f4e4bc] w-full max-w-2xl p-8 rounded border-[12px] border-[#4a3728] shadow-2xl relative animate-scale-in">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 py-3 rounded-b-xl font-cursive text-2xl">{event.title}</div>
                        <div className="text-[#2c1810] leading-relaxed text-lg font-serif italic mb-8">{event.content}</div>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceA.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => setEvent(null)} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceB.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo } from 'react';
import { GameState, ClanMember, Building, Realm, SpecializedTalents } from '../types';
import { BUILDING_TYPES, POSITIONS, REALM_ORDER, RECIPES, CULTIVATION_METHODS, getArtisanTitle, getArtisanBonus } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddBuilding: (type: string) => void;
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    onClose: () => void;
}

type WarehouseSubTab = 'pills' | 'materials' | 'equipment' | 'methods' | 'talismans';

const ClanManagement: React.FC<Props> = ({ state, onUpdateMember, onAddBuilding, onAssignBuilding, onClose }) => {
    const [activeTab, setActiveTab] = useState<'status' | 'buildings' | 'positions' | 'alchemy' | 'smithing' | 'warehouse'>('status');
    const [warehouseSubTab, setWarehouseSubTab] = useState<WarehouseSubTab>('materials');

    const aliveMembers = useMemo(() => state.members.filter(m => m.status !== 'dead'), [state.members]);

    const realmStats = useMemo(() => {
        const stats: Record<string, number> = {};
        let maxRealmIdx = 0;
        aliveMembers.forEach(m => {
            stats[m.realm] = (stats[m.realm] || 0) + 1;
            maxRealmIdx = Math.max(maxRealmIdx, REALM_ORDER.indexOf(m.realm));
        });
        return REALM_ORDER.slice(0, maxRealmIdx + 1).reverse();
    }, [aliveMembers]);

    // Fix for lines 32 and 33: Explicitly cast Object.values to number[] to avoid 'unknown' type errors during reduce arithmetic
    const totalHerbs = useMemo(() => (Object.values(state.inventory.herbs) as number[]).reduce((a, b) => a + b, 0), [state.inventory.herbs]);
    const totalMinerals = useMemo(() => (Object.values(state.inventory.minerals) as number[]).reduce((a, b) => a + b, 0), [state.inventory.minerals]);

    const hasBuilding = (type: string) => state.buildings.some(b => b.type === type && b.isFinished);

    const getBuildingProgress = (b: Building) => {
        const total = BUILDING_TYPES[b.type].baseTurns;
        const current = total - b.turnsRemaining;
        return (current / total) * 100;
    };

    const alchemyRoom = state.buildings.find(b => b.type === 'AlchemyRoom');
    const assignedAlchemist = aliveMembers.find(m => m.id === alchemyRoom?.assignedMemberId);

    const smithyRoom = state.buildings.find(b => b.type === 'Smithy');
    const assignedSmith = aliveMembers.find(m => m.id === smithyRoom?.assignedMemberId);

    const renderBuildingList = (category: string) => {
        const list = Object.entries(BUILDING_TYPES).filter(([_, info]) => info.category === category);
        return (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                {list.map(([type, info]) => {
                    const existing = state.buildings.find(b => b.type === type);
                    const canBuild = !existing && state.spiritStones >= info.baseCost;
                    let reqMet = true;
                    if (info.requirements.realm) {
                        reqMet = aliveMembers.some(m => REALM_ORDER.indexOf(m.realm) >= REALM_ORDER.indexOf(info.requirements.realm!));
                    }
                    if (info.requirements.talent) {
                        const { type: tType, rank } = info.requirements.talent;
                        reqMet = reqMet && aliveMembers.some(m => m.talents.百艺天赋[tType] >= rank);
                    }

                    return (
                        <div key={type} className={`p-4 rounded border transition-all ${existing ? 'bg-black/40 border-yellow-900/30' : 'bg-[#2c1810]/30 border-yellow-900/10'}`}>
                            <div className="flex justify-between items-center mb-2">
                                <span className="text-sm font-bold text-yellow-500">{info.icon} {info.name}</span>
                                <span className="text-[10px] text-yellow-800">✨ {info.baseCost} | ⏳ {info.baseTurns}y</span>
                            </div>
                            <p className="text-[10px] text-gray-500 mb-3">{info.desc}</p>
                            {existing ? (
                                existing.isFinished ? (
                                    <div className="text-[10px] text-green-600 font-bold">已落成</div>
                                ) : (
                                    <div className="w-full h-1.5 bg-black/60 rounded-full overflow-hidden">
                                        <div className="h-full bg-yellow-600 animate-pulse" style={{ width: `${getBuildingProgress(existing)}%` }}></div>
                                    </div>
                                )
                            ) : (
                                <button onClick={() => onAddBuilding(type)} disabled={!canBuild || !reqMet} className={`w-full py-1 text-[10px] rounded border transition-all ${canBuild && reqMet ? 'bg-yellow-900/20 border-yellow-700 text-yellow-400 hover:bg-yellow-700 hover:text-white' : 'bg-gray-800/20 border-gray-700 text-gray-600 opacity-50 cursor-not-allowed'}`}>
                                    {!reqMet ? '资质不足' : '立即营造'}
                                </button>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    };

    const renderWarehouseContent = () => {
        switch (warehouseSubTab) {
            case 'materials':
                return (
                    <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 gap-4">
                        {Object.entries(state.inventory.herbs).map(([name, count]) => (
                            <div key={name} className="bg-black/30 border border-green-900/20 p-3 rounded flex flex-col items-center">
                                <div className="text-2xl mb-1">🌿</div>
                                <span className="text-[10px] text-gray-400 text-center">{name}</span>
                                <span className="text-sm font-bold text-green-500">{count}</span>
                            </div>
                        ))}
                        {Object.entries(state.inventory.minerals).map(([name, count]) => (
                            <div key={name} className="bg-black/30 border border-blue-900/20 p-3 rounded flex flex-col items-center">
                                <div className="text-2xl mb-1">💎</div>
                                <span className="text-[10px] text-gray-400 text-center">{name}</span>
                                <span className="text-sm font-bold text-blue-400">{count}</span>
                            </div>
                        ))}
                        {state.inventory.paper > 0 && (
                            <div className="bg-black/30 border border-yellow-900/20 p-3 rounded flex flex-col items-center">
                                <div className="text-2xl mb-1">📜</div>
                                <span className="text-[10px] text-gray-400 text-center">符纸</span>
                                <span className="text-sm font-bold text-yellow-600">{state.inventory.paper}</span>
                            </div>
                        )}
                    </div>
                );
            case 'pills':
                return (
                    <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 gap-4">
                        {Object.entries(state.inventory.pills).length > 0 ? Object.entries(state.inventory.pills).map(([name, count]) => (
                            <div key={name} className="bg-black/30 border border-pink-900/20 p-3 rounded flex flex-col items-center">
                                <div className="text-2xl mb-1">💊</div>
                                <span className="text-[10px] text-gray-400 text-center">{name}</span>
                                <span className="text-sm font-bold text-pink-500">{count}</span>
                            </div>
                        )) : (
                            <div className="col-span-full py-20 text-center text-gray-700 italic">尚未炼制任何丹药</div>
                        )}
                    </div>
                );
            case 'equipment':
                return (
                    <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 gap-4">
                        {Object.entries(state.inventory.weapons).length > 0 ? Object.entries(state.inventory.weapons).map(([name, count]) => (
                            <div key={name} className="bg-black/30 border border-blue-900/20 p-3 rounded flex flex-col items-center">
                                <div className="text-2xl mb-1">⚔️</div>
                                <span className="text-[10px] text-gray-400 text-center">{name}</span>
                                <span className="text-sm font-bold text-blue-400">{count}</span>
                            </div>
                        )) : (
                            <div className="col-span-full py-20 text-center text-gray-700 italic">家族兵器库空空如也</div>
                        )}
                    </div>
                );
            case 'methods':
                return (
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                        {CULTIVATION_METHODS.map(method => (
                            <div key={method.id} className="bg-black/30 border border-yellow-900/20 p-4 rounded relative overflow-hidden group">
                                <div className="flex justify-between items-start mb-2">
                                    <span className="text-sm font-bold text-yellow-500">{method.name}</span>
                                    <span className="text-[9px] px-1 border border-yellow-900/40 text-yellow-700">{method.grade}阶{method.quality}</span>
                                </div>
                                <p className="text-[10px] text-gray-500 leading-relaxed mb-2">{method.desc}</p>
                                <div className="text-[9px] text-yellow-800/60 italic">效果: {method.bonus}</div>
                                <div className="absolute -bottom-2 -right-2 text-4xl opacity-5 group-hover:opacity-10 transition-opacity">📜</div>
                            </div>
                        ))}
                    </div>
                );
            case 'talismans':
                return (
                    <div className="flex flex-col items-center justify-center py-20">
                        <div className="text-4xl mb-4 opacity-20">🧧</div>
                        <p className="text-gray-600 italic">家族尚未掌握符箓炼制技术，或暂无成品库存</p>
                    </div>
                );
            default:
                return null;
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 overflow-hidden">
            <div className="relative w-full max-w-6xl h-[85vh] bg-[#1a1310] border-[6px] border-[#4a3728] rounded-sm shadow-2xl flex flex-col">
                <div className="h-14 bg-[#2c1810] border-b border-yellow-900/30 flex items-center px-6 shrink-0 gap-8">
                    <h2 className="text-xl font-cursive text-yellow-500">🏯 望月大社</h2>
                    <div className="flex h-full overflow-x-auto scrollbar-hide">
                        <button onClick={() => setActiveTab('status')} className={`whitespace-nowrap px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'status' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>家族概况</button>
                        <button onClick={() => setActiveTab('warehouse')} className={`whitespace-nowrap px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'warehouse' ? 'border-amber-500 text-amber-500 bg-amber-900/10' : 'border-transparent text-gray-500'}`}>家族仓库</button>
                        <button onClick={() => setActiveTab('buildings')} className={`whitespace-nowrap px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'buildings' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>建筑营造</button>
                        <button onClick={() => setActiveTab('positions')} className={`whitespace-nowrap px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'positions' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500'}`}>职位册封</button>
                        {hasBuilding('AlchemyRoom') && <button onClick={() => setActiveTab('alchemy')} className={`whitespace-nowrap px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'alchemy' ? 'border-pink-500 text-pink-500 bg-pink-900/10' : 'border-transparent text-gray-500'}`}>炼丹</button>}
                        {hasBuilding('Smithy') && <button onClick={() => setActiveTab('smithing')} className={`whitespace-nowrap px-4 h-full text-xs font-bold border-b-2 transition-all ${activeTab === 'smithing' ? 'border-blue-500 text-blue-500 bg-blue-900/10' : 'border-transparent text-gray-500'}`}>炼器</button>}
                    </div>
                    <button onClick={onClose} className="ml-auto min-w-[32px] w-8 h-8 flex items-center justify-center text-gray-500 hover:text-white text-2xl">×</button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
                    {activeTab === 'status' && (
                        <div className="space-y-8 animate-fade-in">
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <div className="p-4 bg-black/30 border border-yellow-900/20 rounded">
                                    <h3 className="text-yellow-600 text-[10px] font-bold uppercase mb-4 tracking-widest">资源统计</h3>
                                    <div className="space-y-2 text-sm text-white">
                                        <div className="flex justify-between"><span className="text-gray-500">家族灵石</span><span className="text-yellow-400 font-bold">{state.spiritStones}</span></div>
                                        <div className="flex justify-between"><span className="text-gray-500">功德点</span><span className="text-blue-400 font-bold">{state.merit}</span></div>
                                        <div className="flex justify-between"><span className="text-gray-500">家族底蕴</span><span className="text-purple-400 font-bold">{state.heritagePool}</span></div>
                                    </div>
                                </div>
                                <div className="p-4 bg-black/30 border border-yellow-900/20 rounded">
                                    <h3 className="text-blue-600 text-[10px] font-bold uppercase mb-4 tracking-widest">境界分布</h3>
                                    <div className="space-y-2 text-sm text-white">
                                        {realmStats.map(r => (
                                            <div key={r} className="flex justify-between"><span className="text-gray-500">{r}</span><span className="text-gray-200">{state.members.filter(m => m.status !== 'dead' && m.realm === r).length} 人</span></div>
                                        ))}
                                    </div>
                                </div>
                                <div className="p-4 bg-black/30 border border-yellow-900/20 rounded">
                                    <h3 className="text-green-600 text-[10px] font-bold uppercase mb-4 tracking-widest">物产仓库</h3>
                                    <div className="space-y-2 text-sm text-white">
                                        <div className="flex justify-between"><span className="text-gray-500">药材总量</span><span className="text-green-400 font-bold">{totalHerbs}</span></div>
                                        <div className="flex justify-between"><span className="text-gray-500">矿石总量</span><span className="text-gray-400 font-bold">{totalMinerals}</span></div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                    {activeTab === 'warehouse' && (
                        <div className="flex flex-col h-full animate-fade-in">
                            <div className="flex gap-2 mb-6 border-b border-yellow-900/10 pb-4 overflow-x-auto scrollbar-hide">
                                <button onClick={() => setWarehouseSubTab('materials')} className={`px-4 py-1.5 rounded text-[11px] font-bold transition-all ${warehouseSubTab === 'materials' ? 'bg-amber-900 text-amber-100 shadow-lg' : 'bg-black/20 text-gray-500 hover:text-gray-300'}`}>🏮 材料</button>
                                <button onClick={() => setWarehouseSubTab('pills')} className={`px-4 py-1.5 rounded text-[11px] font-bold transition-all ${warehouseSubTab === 'pills' ? 'bg-pink-900/40 text-pink-200' : 'bg-black/20 text-gray-500 hover:text-gray-300'}`}>💊 丹药</button>
                                <button onClick={() => setWarehouseSubTab('equipment')} className={`px-4 py-1.5 rounded text-[11px] font-bold transition-all ${warehouseSubTab === 'equipment' ? 'bg-blue-900/40 text-blue-200' : 'bg-black/20 text-gray-500 hover:text-gray-300'}`}>⚔️ 装备</button>
                                <button onClick={() => setWarehouseSubTab('methods')} className={`px-4 py-1.5 rounded text-[11px] font-bold transition-all ${warehouseSubTab === 'methods' ? 'bg-yellow-900/40 text-yellow-200' : 'bg-black/20 text-gray-500 hover:text-gray-300'}`}>📜 功法</button>
                                <button onClick={() => setWarehouseSubTab('talismans')} className={`px-4 py-1.5 rounded text-[11px] font-bold transition-all ${warehouseSubTab === 'talismans' ? 'bg-red-900/40 text-red-200' : 'bg-black/20 text-gray-500 hover:text-gray-300'}`}>🧧 符箓</button>
                            </div>
                            <div className="flex-1">
                                {renderWarehouseContent()}
                            </div>
                        </div>
                    )}
                    {activeTab === 'buildings' && (
                        <div className="space-y-8 animate-fade-in">
                            <div><h3 className="text-yellow-700 text-xs font-bold mb-4 border-l-4 border-yellow-700 pl-3">资源建筑 (Resource)</h3>{renderBuildingList('Resource')}</div>
                            <div><h3 className="text-blue-700 text-xs font-bold mb-4 border-l-4 border-blue-700 pl-3">功能建筑 (Functional)</h3>{renderBuildingList('Functional')}</div>
                            <div><h3 className="text-emerald-700 text-xs font-bold mb-4 border-l-4 border-emerald-700 pl-3">基础建筑 (Base)</h3>{renderBuildingList('Base')}</div>
                        </div>
                    )}
                    {activeTab === 'alchemy' && (
                        <div className="flex gap-6 h-full animate-fade-in">
