                                                    <span className="text-pink-300">{assignedAlchemist.proficiencies.炼丹}</span>
                                                </div>
                                                {getArtisanBonus(assignedAlchemist.talents.百艺天赋.炼丹) > 0 && (
                                                    <p className="text-green-500 text-[9px] mt-1 font-bold">
                                                        天赋加成: +{getArtisanBonus(assignedAlchemist.talents.百艺天赋.炼丹)}% 成功率
                                                    </p>
