                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500 hover:text-gray-300'}`}>英灵祠堂</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2 scrollbar-hide">
                {activeTab === 'alive' && (
                    <button onClick={onAddMember} className="w-full bg-green-900/20 hover:bg-green-800/40 text-green-400 border border-green-900/50 py-2 rounded text-xs transition-all flex items-center justify-center gap-2 mb-4 group">
                        <span>👶</span> 诞育麟儿
                    </button>
                )}
                {pagedMembers.length > 0 ? pagedMembers.map(member => (
