                        key={member.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(member.id)}
                        className={`group p-3 rounded-md border transition-all cursor-pointer ${selectedMemberId === member.id ? 'bg-[#2d1e15] border-yellow-600 scale-[1.02] shadow-xl' : 'bg-[#1e130c] border-yellow-900/30 hover:border-yellow-700/50'}`}
                    >
                        <div className="flex justify-between items-start mb-1">
                            <div className="flex items-center gap-2">
                                <span className="font-bold text-sm text-yellow-100/90">{member.name}</span>
                                <span className="text-[8px] text-[#8c6b4f]">[{member.position}]</span>
                                {member.assignment === 'Cultivation' && member.realm !== Realm.Mortal && <span className="text-[8px] animate-pulse text-blue-400">修炼中</span>}
                            </div>
                            <button className={`text-[9px] px-2 py-0.5 rounded border shadow-sm hover:brightness-125 transition-all ${getRealmStyle(member.realm)}`}>
