import React, { useState, useMemo, useCallback } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType, TalentTier, RootGrade, SpecializedTalents } from '../types';
import { TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, POSITIONS, PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus, getWeaponMasteryTitle, getWeaponTalentBonus, ITEM_DETAILS } from '../constants';

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
}

const ITEMS_PER_PAGE = 8;
const MAX_BAG_SLOTS = 20;

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'bag'>('attr');
    const [bagSubTab, setBagSubTab] = useState<'all' | 'equipment' | 'pills' | 'materials' | 'methods'>('all');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<string | null>(null);
    const [focusedLibraryMethodId, setFocusedLibraryMethodId] = useState<string | null>(null);

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const getTierColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-slate-400';
            case '平庸': return 'text-gray-300';
            case '普通': return 'text-emerald-500';
            case '超凡': return 'text-sky-500';
            case '天才': return 'text-purple-500';
            case '绝世': return 'text-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]';
            case '绝世天骄': return 'text-rose-500 animate-pulse font-black shadow-[0_0_12px_rgba(244,63,94,0.6)]';
            default: return 'text-gray-400';
        }
    };

    const getTitleColor = (tier: TalentTier) => {
        switch (tier) {
            case '凡人': return 'text-white';
            case '平庸': return 'text-green-500';
            case '普通': return 'text-blue-400';
            case '超凡': return 'text-purple-500';
            case '天才': return 'text-orange-500';
            case '绝世': return 'text-amber-400';
            case '绝世天骄': return 'text-red-600';
            default: return 'text-white';
        }
    };

    const getRootGradeColor = (grade: RootGrade) => {
        switch (grade) {
            case '凡人': return 'text-slate-500';
            case '伪灵根': return 'text-gray-400';
            case '下品灵根': return 'text-emerald-600';
            case '中品灵根': return 'text-sky-600';
            case '极品灵根': return 'text-amber-600 font-bold';
            default: return 'text-gray-400';
        }
    };

    const getGradeColor = (grade: number | string | undefined) => {
        if (typeof grade === 'string') return 'border-purple-500 text-purple-400 shadow-[0_0_5px_rgba(168,85,247,0.3)]';
        const g = Number(grade) || 0;
        if (g <= 0) return 'border-slate-400 text-slate-300 bg-slate-500/10';
        if (g <= 1) return 'border-slate-300 text-slate-100 bg-slate-500/10 shadow-[0_0_5px_rgba(255,255,255,0.1)]';
        if (g <= 4) return 'border-emerald-500 text-emerald-400 bg-emerald-500/10 shadow-[0_0_8px_rgba(16,185,129,0.2)]';
        if (g <= 6) return 'border-sky-500 text-sky-400 bg-sky-500/10 shadow-[0_0_10px_rgba(14,165,233,0.3)]';
        if (g === 7) return 'border-orange-500 text-orange-400 bg-orange-500/10 shadow-[0_0_12px_rgba(249,115,22,0.4)]';
        if (g >= 8) return 'border-yellow-500 text-yellow-400 bg-yellow-500/10 shadow-[0_0_15px_rgba(234,179,8,0.5)]';
        return 'border-slate-400 text-slate-300';
    };

    const getRealmStyle = (realm: Realm) => {
        if (realm === Realm.Mortal) return "border-[#4a3728] bg-[#2c1e15] text-[#8c6b4f]";
        return "border-[#6b4e31] bg-[#3d2b1f] text-[#c9a063]";
    };

    const getRealmText = (realm: Realm, subRealm: number) => {
        if (realm === Realm.Mortal) return '凡人';
        return `${realm}${subRealm}层`;
    };

    const getGradeText = (method: CultivationMethod) => {
        const numerals = ['','一','二','三','四','五','六','七','八','九'];
        return `${numerals[method.grade]}品${method.quality}`;
    };

    const toggleMethod = (methodId: string, type: MethodType) => {
        if (!selectedMember) return;

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
        setFocusedLibraryMethodId(null);
    };

    const libraryMethods = useMemo(() => {
        if (!selectedMember) return [];
        return CULTIVATION_METHODS.filter(m => {
            if (m.type !== libraryType) return false;
            const isOwnedByClan = (state.inventory.methods[m.name] || 0) > 0;
            const isOwnedBySelf = (selectedMember.personalInventory.methods[m.name] || 0) > 0;
            const isEquipped = selectedMember.mainMethodId === m.id || 
                             selectedMember.movementMethodId === m.id || 
                             selectedMember.auxMethodIds.includes(m.id);
            return isOwnedByClan || isOwnedBySelf || isEquipped;
        });
    }, [libraryType, selectedMember, state.inventory.methods]);

    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;
        if (rect.top < 300) { y = rect.bottom + 12; } else { y = rect.top - 12; }
        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;
        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                    {getGradeText(method)}
                </span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-400 mb-3 leading-relaxed italic">{method.desc}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                {method.buffs.cultivationSpeed && (
                    <div className="flex justify-between text-[10px]">
                        <span className="text-gray-500">修炼速度</span>
                        <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                            {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                        </span>
                    </div>
                )}
                <p className="text-[9px] text-yellow-600/80 mt-2 italic">"{method.bonus}"</p>
            </div>
        </div>
    );

    const renderItemTooltipContent = (itemName: string) => {
        const details = ITEM_DETAILS[itemName];
        if (!details) return <div>未知物品：{itemName}</div>;
        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{itemName}</span>
                    <span className={`text-[9px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(details.grade)}`}>
                        {details.grade ? (typeof details.grade === 'number' ? `${details.grade}阶` : details.grade) : '凡物'}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-400 mb-3 leading-relaxed italic">{details.desc}</p>
                {details.effect && (
                    <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                        <p className="text-[10px] text-orange-400 font-bold">【物品效果】</p>
                        <p className="text-[10px] text-gray-300">{details.effect}</p>
                    </div>
                )}
            </div>
        );
    };

    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemName = selectedMember.equippedItems[slot];
        if (!itemName) return;
        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };
        if (slot === 'weapon') {
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        } else {
            newInventory.weapons[itemName] = (newInventory.weapons[itemName] || 0) + 1;
        }
        onUpdateMember(selectedMember.id, { equippedItems: newEquipped, personalInventory: newInventory });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemName: string, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;
        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };
        const currentItem = newEquipped[category];
        if (currentItem) { newInventory.weapons[currentItem] = (newInventory.weapons[currentItem] || 0) + 1; }
        if (newInventory.weapons[itemName] > 0) {
            newInventory.weapons[itemName]--;
            if (newInventory.weapons[itemName] === 0) delete newInventory.weapons[itemName];
        }
        newEquipped[category] = itemName;
        onUpdateMember(selectedMember.id, { equippedItems: newEquipped, personalInventory: newInventory });
        setFocusedBagItem(null);
    };

    const renderNamePlaque = (member: ClanMember) => (
        <div className={`border-2 border-black bg-red-950/60 px-6 py-2 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-sm ${member.tier === '绝世天骄' ? 'ring-1 ring-red-500/50' : ''}`}>
            <h2 className="text-xl sm:text-2xl lg:text-3xl font-cursive tracking-wider text-center whitespace-nowrap">
                <span className="text-yellow-400">{member.name}</span>
                {member.title && (
                    <>
                        <span className="mx-1 text-black font-bold">·</span>
                        <span className={`${getTitleColor(member.tier)}`}>{member.title}</span>
                    </>
                )}
            </h2>
        </div>
    );

    const renderSlotItem = (methodId: string | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;
        return (
            <div className="flex flex-col items-center gap-1 group">
                <div 
                    onClick={() => methodId && setFocusedSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => method && showTooltip(e, renderMethodTooltipContent(method))}
                    onMouseLeave={hideTooltip}
                    className={`relative cursor-pointer transition-all duration-300 rounded flex items-center justify-center 
                        ${type === 'Cultivation' ? 'w-16 h-16 sm:w-24 sm:h-24 border-4 border-yellow-600/20' : 'w-12 h-12 sm:w-16 sm:h-16 border-2 border-yellow-900/20'} 
                        bg-black/50 overflow-hidden hover:border-yellow-500/50`}
                >
                    {method ? (
                        <div className={`w-full h-full border-2 p-1 flex flex-col items-center justify-center text-center font-bold ${getGradeColor(method.grade)}`}>
                            <span className={type === 'Cultivation' ? 'text-[10px] sm:text-xs' : 'text-[7px] sm:text-[8px]'}>{method.name}</span>
                        </div>
                    ) : (
                        <div className="text-gray-800 text-[8px] sm:text-[10px] opacity-40 italic">{label}</div>
                    )}
                    {methodId && isFocused && (
                        <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center p-1 animate-fade-in z-20">
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleMethod(methodId, type); hideTooltip(); }}
                                className="bg-red-900/80 hover:bg-red-700 text-white text-[9px] sm:text-[10px] py-1 px-3 rounded-full border border-red-500/50 shadow-lg"
                            >卸下</button>
                        </div>
                    )}
                </div>
                <span className="text-[8px] sm:text-[10px] text-yellow-700/80 font-bold bg-black/30 px-2 sm:px-3 py-0.5 rounded-full border border-yellow-900/10">{label}</span>
            </div>
        );
    };

    const renderEquipSlot = (item: string | null, label: string, icon: string, slotKey: keyof ClanMember['equippedItems']) => {
        const isFocused = focusedEquipSlot === slotKey;
        const isLeftSide = slotKey === 'weapon' || slotKey === 'armor';
        return (
            <div className="flex flex-col items-center gap-1 relative">
                <div 
                    onClick={() => item && setFocusedEquipSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => item && showTooltip(e, renderItemTooltipContent(item))}
                    onMouseLeave={hideTooltip}
                    className={`w-12 h-12 sm:w-16 sm:h-16 rounded border-2 flex items-center justify-center transition-all bg-black/40 hover:border-yellow-500/50 cursor-pointer relative overflow-hidden ${item ? 'border-yellow-600 text-yellow-400 font-bold text-[10px] px-1 text-center shadow-[inset_0_0_15px_rgba(234,179,8,0.15)]' : 'border-white/10 text-gray-800'}`}>
                    {item ? item : icon}
                    {item && isFocused && ( <div className="absolute inset-0 border-2 border-yellow-400/60 animate-pulse pointer-events-none"></div> )}
                </div>
                {item && isFocused && (
                    <button 
                        onClick={(e) => { e.stopPropagation(); handleUnequip(slotKey); hideTooltip(); }}
                        className={`absolute top-1/2 -translate-y-1/2 z-30 bg-red-800 hover:bg-red-700 text-white text-[10px] py-1 px-2 rounded-sm font-bold shadow-[0_0_12px_rgba(239,68,68,0.5)] border border-red-500 transition-all active:scale-95 whitespace-nowrap
                            ${isLeftSide ? '-right-10 sm:-right-12' : '-left-10 sm:-left-12'}`}
                    >卸下</button>
                )}
                <span className="text-[10px] text-gray-600 mt-1">{label}</span>
            </div>
        );
    };

    // --- 物品行囊核心渲染 ---
    const renderBagGrid = () => {
        if (!selectedMember) return null;
        const inv = selectedMember.personalInventory;

        // 聚合物品数据
        let allItems: { name: string, count: number, type: string }[] = [];

        if (bagSubTab === 'all' || bagSubTab === 'equipment') {
            Object.entries(inv.weapons).forEach(([name, count]) => allItems.push({ name, count, type: 'weapon' }));
        }
        if (bagSubTab === 'all' || bagSubTab === 'pills') {
            Object.entries(inv.pills).forEach(([name, count]) => allItems.push({ name, count, type: 'pill' }));
        }
        if (bagSubTab === 'all' || bagSubTab === 'materials') {
            Object.entries(inv.herbs).forEach(([name, count]) => allItems.push({ name, count, type: 'herb' }));
            Object.entries(inv.minerals).forEach(([name, count]) => allItems.push({ name, count, type: 'mineral' }));
        }
        if (bagSubTab === 'all' || bagSubTab === 'methods') {
            Object.entries(inv.methods).forEach(([name, count]) => allItems.push({ name, count, type: 'method' }));
        }

        const slots = Array.from({ length: MAX_BAG_SLOTS });

        return (
            <div className="grid grid-cols-4 sm:grid-cols-5 gap-3 p-4 bg-black/20 rounded-xl border border-white/5 shadow-inner h-fit max-w-md mx-auto">
                {slots.map((_, idx) => {
                    const item = allItems[idx];
                    if (!item) return <div key={idx} className="aspect-square bg-black/40 border border-white/5 rounded-lg flex items-center justify-center text-gray-900/40 text-xs">·</div>;

                    const methodData = item.type === 'method' ? CULTIVATION_METHODS.find(m => m.name === item.name) : null;
                    const isEquipped = methodData && (selectedMember.mainMethodId === methodData.id || selectedMember.movementMethodId === methodData.id || selectedMember.auxMethodIds.includes(methodData.id));
                    const isFocused = focusedBagItem === item.name;

                    return (
                        <div 
                            key={idx}
                            onClick={() => setFocusedBagItem(isFocused ? null : item.name)}
                            onMouseEnter={(e) => showTooltip(e, methodData ? renderMethodTooltipContent(methodData) : renderItemTooltipContent(item.name))}
                            onMouseLeave={hideTooltip}
                            className={`aspect-square relative flex flex-col items-center justify-center p-1 rounded-lg border-2 transition-all cursor-pointer shadow-lg overflow-hidden group
                                ${methodData ? getGradeColor(methodData.grade) : 'bg-black/60 border-yellow-900/20 hover:border-yellow-500/50'}
                                ${isEquipped ? 'opacity-40 grayscale' : ''}`}
                        >
                            <span className="text-2xl sm:text-3xl filter drop-shadow-md">
                                {item.type === 'weapon' ? '⚔️' : item.type === 'pill' ? '💊' : item.type === 'herb' ? '🌿' : item.type === 'mineral' ? '💎' : '📜'}
                            </span>
                            <span className="absolute bottom-0.5 right-1 text-[9px] font-mono font-bold text-white drop-shadow-sm">{item.count > 1 ? item.count : ''}</span>

                            {isFocused && !isEquipped && (
                                <div className="absolute inset-0 bg-black/80 flex items-center justify-center z-20 animate-fade-in p-1">
                                    {item.type === 'weapon' ? (
                                        <button onClick={(e) => { e.stopPropagation(); handleEquip(item.name, 'weapon'); hideTooltip(); }} className="bg-yellow-700 text-white text-[9px] py-1 px-2 rounded font-bold">佩戴</button>
                                    ) : item.type === 'method' && methodData ? (
                                        <button onClick={(e) => { e.stopPropagation(); toggleMethod(methodData.id, methodData.type); setFocusedBagItem(null); hideTooltip(); }} className="bg-emerald-700 text-white text-[9px] py-1 px-2 rounded font-bold">研习</button>
                                    ) : (
                                        <span className="text-[8px] text-gray-400">不可研习</span>
                                    )}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        );
    };

    /**
     * Fix: Implement renderCultivationTab to manage cultivation methods configuration.
     */
    const renderCultivationTab = () => {
        if (!selectedMember) return null;

        return (
            <div className="space-y-8 animate-fade-in">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                    {/* 当前配置 */}
                    <div className="bg-black/20 p-6 rounded-xl border border-yellow-900/10">
                        <h4 className="text-yellow-600 text-[11px] font-bold uppercase tracking-[0.2em] mb-6 flex items-center gap-2">
                            <span>☯️</span> 功法配置
                        </h4>
                        <div className="flex flex-wrap justify-center gap-6">
                            {renderSlotItem(selectedMember.mainMethodId, 'Cultivation', '主修功法', 'main')}
                            {renderSlotItem(selectedMember.movementMethodId, 'Movement', '身法步法', 'move')}
                        </div>
                        <div className="mt-8">
                            <h5 className="text-[10px] text-gray-500 mb-4 text-center uppercase tracking-widest">辅助/战斗秘籍 (最多4门)</h5>
                            <div className="flex justify-center gap-4">
                                {[0, 1, 2, 3].map(idx => (
                                    <div key={idx}>
                                        {renderSlotItem(selectedMember.auxMethodIds[idx] || null, 'Combat', `秘籍 ${idx + 1}`, `aux-${idx}`)}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* 功法选择库 */}
                    <div className="bg-black/20 p-6 rounded-xl border border-yellow-900/10 flex flex-col">
                        <div className="flex justify-between items-center mb-6">
                            <h4 className="text-yellow-600 text-[11px] font-bold uppercase tracking-[0.2em]">藏经阁/行囊</h4>
                            <div className="flex gap-1 bg-black/40 p-1 rounded-lg border border-yellow-900/20">
                                <button onClick={() => setLibraryType('Cultivation')} className={`px-3 py-1 text-[9px] rounded font-bold transition-all ${libraryType === 'Cultivation' ? 'bg-yellow-800 text-yellow-100' : 'text-gray-500'}`}>主修</button>
                                <button onClick={() => setLibraryType('Movement')} className={`px-3 py-1 text-[9px] rounded font-bold transition-all ${libraryType === 'Movement' ? 'bg-yellow-800 text-yellow-100' : 'text-gray-500'}`}>身法</button>
                                <button onClick={() => setLibraryType('Combat')} className={`px-3 py-1 text-[9px] rounded font-bold transition-all ${libraryType === 'Combat' ? 'bg-yellow-800 text-yellow-100' : 'text-gray-500'}`}>秘籍</button>
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto space-y-2 max-h-[300px] pr-2 custom-scrollbar">
                            {libraryMethods.length > 0 ? libraryMethods.map(method => {
                                const isEquipped = selectedMember.mainMethodId === method.id || 
                                                 selectedMember.movementMethodId === method.id || 
                                                 selectedMember.auxMethodIds.includes(method.id);
                                const isFocused = focusedLibraryMethodId === method.id;

                                return (
                                    <div 
                                        key={method.id}
                                        onClick={() => setFocusedLibraryMethodId(isFocused ? null : method.id)}
                                        onMouseEnter={(e) => showTooltip(e, renderMethodTooltipContent(method))}
                                        onMouseLeave={hideTooltip}
                                        className={`p-3 rounded border transition-all cursor-pointer flex justify-between items-center group
                                            ${isEquipped ? 'bg-emerald-950/20 border-emerald-900/30' : 'bg-black/40 border-yellow-900/10 hover:border-yellow-700/50'}
                                            ${isFocused ? 'ring-1 ring-yellow-500' : ''}`}
                                    >
                                        <div className="flex flex-col">
                                            <div className="flex items-center gap-2">
                                                <span className={`text-xs font-bold ${isEquipped ? 'text-emerald-400' : 'text-yellow-100'}`}>{method.name}</span>
                                                <span className={`text-[8px] px-1 rounded border ${getGradeColor(method.grade)}`}>{getGradeText(method)}</span>
                                            </div>
                                            <span className="text-[9px] text-gray-600 mt-1 italic">{method.bonus}</span>
                                        </div>
                                        {isFocused && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); toggleMethod(method.id, method.type); hideTooltip(); }}
                                                className={`px-3 py-1 rounded text-[9px] font-bold transition-all border
                                                    ${isEquipped ? 'bg-red-900/20 border-red-900/50 text-red-400' : 'bg-yellow-900/20 border-yellow-700 text-yellow-400 hover:bg-yellow-700 hover:text-white'}`}
                                            >
                                                {isEquipped ? '卸下' : '研习'}
                                            </button>
                                        )}
                                    </div>
                                );
                            }) : (
                                <div className="py-20 text-center text-gray-700 italic text-[10px]">家族暂无此类功法</div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        );
