                                                <button onClick={() => setBagSubTab('equipment')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'equipment' ? 'bg-blue-900/40 text-blue-200' : 'text-gray-500 hover:text-gray-300'}`}>装备</button>
                                                <button onClick={() => setBagSubTab('pills')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'pills' ? 'bg-pink-900/40 text-pink-200' : 'text-gray-500 hover:text-gray-300'}`}>丹药</button>
                                                <button onClick={() => setBagSubTab('materials')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'materials' ? 'bg-emerald-900/40 text-emerald-200' : 'text-gray-500 hover:text-gray-300'}`}>材料</button>
                                                <button onClick={() => setBagSubTab('methods')} className={`px-4 sm:px-6 py-2 text-xs rounded-lg transition-all font-bold ${bagSubTab === 'methods' ? 'bg-amber-900/40 text-amber-200' : 'text-gray-500 hover:text-gray-300'}`}>功法</button>
                                            </div>
                                            <div className="flex-1 overflow-y-auto">
                                                {renderBagGrid()}
                                                <div className="mt-4 text-center text-[10px] text-gray-700 uppercase tracking-widest font-bold">乾坤行囊 · 固定20格</div>
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'cultivation' && renderCultivationTab()}

                                    {detailTab === 'talents' && (
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-fade-in text-gray-200">
                                            <div>
                                                <h4 className="text-red-700 text-[11px] font-bold uppercase tracking-[0.3em] border-b border-red-900/20 pb-2 mb-6">战斗天赋</h4>
                                                {Object.entries(selectedMember.talents.战斗天赋).map(([key, val]) => (
                                                    <div key={key} className="flex justify-between mb-2"><span>{key}:</span><span>{val}</span></div>
                                                ))}
                                            </div>
                                        </div>
                                    )}
                                    {/* ... tasks and plan tabs same as before ... */}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

